-- 20. Create a trigger to prevent negative discount
create trigger trg_prevent_negative_discount
before insert on orders
for each row
begin
    if new.discount < 0 then
        set new.discount = 0;
    end if;
end;    

insert into orders  values (1012, 213, 140, '2024-01-03', 500.00, -20.00, 'UPI', 20); 
-- discount will be set to 0 due to trigger
select * from orders where order_id = 1012;

-- 21. Create delivery delay warning trigger
create table delivery_delay_log (
    log_id INT PRIMARY KEY AUTO_INCREMENT,
    order_id INT,
    customer_id INT,
    restaurant_id INT,
    delivery_time INT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

create trigger log_late_delivery
AFTER INSERT ON orders
for each row
BEGIN
    IF NEW.delivery_time > 45 THEN
        INSERT INTO delivery_delay_log (order_id, customer_id, restaurant_id, delivery_time)
        VALUES (NEW.order_id, NEW.customer_id, NEW.restaurant_id, NEW.delivery_time);
    END IF;
END;

